ALGORITHM OptimalBST(p[], q[], n)
// p[1..n] = successful search probabilities
// q[0..n] = unsuccessful search probabilities (dummy keys)
// n = number of keys
OUTPUT: Minimum cost and root table for constructing the OBST

BEGIN
 // Step 1: Initialize base cases
 // For subtrees with no real keys, cost = probability of dummy key
 FOR i = 0 TO n DO
 cost[i][i] = q[i]
 weight[i][i] = q[i]
 root[i][i] = i // No root for empty subtree
 END FOR

 // Step 2: Fill tables for subproblems of increasing length
 FOR length = 1 TO n DO
 // length = number of keys in the subtree
 FOR i = 0 TO n-length DO
 j = i + length // subtree spans keys k_{i+1} to k_j

 // Step 2a: Compute weight w[i][j]
 weight[i][j] = weight[i][j-1] + p[j] + q[j]

 // Step 2b: Initialize cost to infinity
 cost[i][j] = INFINITY

 // Step 2c: Try each possible root and find minimum
 // Try k_r as root where r ranges from i+1 to j
 FOR r = i+1 TO j DO
 // Cost if k_r is root:
 // Left subtree: cost[i][r-1], Right subtree: cost[r][j]
 // Total = left cost + right cost + weight (depth increase)
 current_cost = cost[i][r-1] + cost[r][j]

 IF current_cost < cost[i][j] THEN
 cost[i][j] = current_cost
 root[i][j] = r
 END IF
 END FOR

 // Step 2d: Add weight (cost of searching deeper)
 cost[i][j] = cost[i][j] + weight[i][j]
 END FOR
 END FOR

 // Step 3: Return minimum cost and root table
 RETURN cost[0][n], root[][]
END ALGORITHM

// ALGORITHM: ConstructTreeFromRoot
// Uses root table to build the actual BST structure
ALGORITHM ConstructTree(root[], i, j, level)
// i, j are indices in root table
// level is the current depth in the tree
BEGIN
 IF i >= j THEN
 // No keys in this range, return NULL
 RETURN NULL
 END IF

 r = root[i][j] // Get root key index

 PRINT "Key k_" + r + " at depth " + level

 // Recursively build left subtree: keys k_{i+1} to k_{r-1}
 IF r > i+1 THEN
 ConstructTree(root, i, r-1, level+1)
 END IF

 // Recursively build right subtree: keys k_{r+1} to k_j
 IF r < j THEN
 ConstructTree(root, r, j, level+1)
 END IF
END ALGORITHM

#include <stdio.h>
#include <float.h>

#define MAX 100

/* Global tables for cost, weight, and root */
float cost[MAX][MAX];
float weight[MAX][MAX];
int root[MAX][MAX];

/*
 * Optimal Binary Search Tree using Dynamic Programming
 * 
 * p[1..n] - successful search probabilities
 * q[0..n] - unsuccessful search probabilities (dummy keys)
 * n - number of keys
 */
void optimalBST(float p[], float q[], int n) {
 int i, j, r, length;
 float minCost, currentCost;

 /* Step 1: Initialize base cases */
 /* For subtrees with no real keys, cost = probability of dummy key */
 for (i = 0; i <= n; i++) {
 cost[i][i] = q[i];
 weight[i][i] = q[i];
 root[i][i] = i; /* No root for empty subtree */
 }

 /* Step 2: Fill tables for subproblems of increasing length */
 /* length = number of keys in the subtree */
 for (length = 1; length <= n; length++) {
 for (i = 0; i <= n - length; i++) {
 j = i + length; /* subtree spans keys k_{i+1} to k_j */

 /* Compute weight w[i][j] */
 weight[i][j] = weight[i][j-1] + p[j] + q[j];

 /* Initialize cost to infinity */
 cost[i][j] = FLT_MAX;

 /* Try each possible root and find minimum */
 minCost = FLT_MAX;
 for (r = i + 1; r <= j; r++) {
 /* Cost if k_r is root: left cost + right cost */
 currentCost = cost[i][r-1] + cost[r][j];

 if (currentCost < minCost) {
 minCost = currentCost;
 root[i][j] = r;
 }
 }

 /* Add weight (cost of searching deeper by 1 level) */
 cost[i][j] = minCost + weight[i][j];
 }
 }
}

/* Recursively construct and print tree structure */
void printTree(int keys[], int i, int j, int level) {
 if (i >= j) {
 return; /* No keys in this range */
 }

 int r = root[i][j];

 /* Print indentation for tree visualization */
 for (int k = 0; k < level; k++) {
 printf(" ");
 }
 printf("├── k%d = %d (depth %d)\n", r, keys[r-1], level);

 /* Recursively print left subtree */
 if (r > i + 1) {
 printTree(keys, i, r - 1, level + 1);
 }

 /* Recursively print right subtree */
 if (r < j) {
 printTree(keys, r, j, level + 1);
 }
}

/* Print the DP tables */
void printTables(int n) {
 int i, j;

 printf("\n=== COST TABLE (c[i][j]) ===\n");
 printf(" ");
 for (j = 0; j <= n; j++) {
 printf("j=%-2d ", j);
 }
 printf("\n");

 for (i = 0; i <= n; i++) {
 printf("i=%d: ", i);
 for (j = 0; j <= n; j++) {
 if (j >= i) {
 printf("%.3f ", cost[i][j]);
 } else {
 printf(" - ");
 }
 }
 printf("\n");
 }

 printf("\n=== ROOT TABLE (root[i][j]) ===\n");
 printf(" ");
 for (j = 0; j <= n; j++) {
 printf("j=%d ", j);
 }
 printf("\n");

 for (i = 0; i <= n; i++) {
 printf("i=%d: ", i);
 for (j = 0; j <= n; j++) {
 if (j >= i) {
 printf(" %d ", root[i][j]);
 } else {
 printf(" - ");
 }
 }
 printf("\n");
 }
}

int main() {
 int n = 4;
 int keys[] = {10, 20, 30, 40};

 /* Probabilities - using 1-based indexing for p */
 float p[] = {0, 0.10, 0.20, 0.05, 0.15}; /* p[1] to p[4] */
 float q[] = {0.05, 0.10, 0.10, 0.05, 0.20}; /* q[0] to q[4] */

 /* Verify probabilities sum to 1 */
 float total = 0;
 for (int i = 1; i <= n; i++) total += p[i];
 for (int i = 0; i <= n; i++) total += q[i];
 printf("Total probability: %.2f\n", total);

 /* Compute optimal BST */
 optimalBST(p, q, n);

 /* Display results */
 printf("\n==================================================\n");
 printf("OPTIMAL BINARY SEARCH TREE RESULTS\n");
 printf("==================================================\n");
 printf("Minimum expected search cost: %.3f\n", cost[0][n]);
 printf("Number of comparisons (worst case): %d\n", n + 1);

 /* Print DP tables */
 printTables(n);

 /* Print tree structure */
 printf("\n=== TREE STRUCTURE ===\n");
 printTree(keys, 0, n, 0);

 return 0;
}
